export function StarIcon({
  light = false,
  half = false,
}: {
  light?: boolean;
  half?: boolean;
}) {
  const id = React.useId();

  return (
    <svg
      width="14"
      height="13"
      viewBox="0 0 14 13"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      {half && (
        <defs>
          <linearGradient id={id}>
            <stop offset="50%" stopColor="#FFC83B" />
            <stop offset="50%" stopColor="#D9D9D9" />
          </linearGradient>
        </defs>
      )}
      <path
        d="M2.55 12.6667L3.63333 7.98333L0 4.83333L4.8 4.41667L6.66667 0L8.53333 4.41667L13.3333 4.83333L9.7 7.98333L10.7833 12.6667L6.66667 10.1833L2.55 12.6667Z"
        fill={half ? `url(#${id})` : light ? "#FFC83B" : "#D9D9D9"}
      />
    </svg>
  );
}

